import novamind_api as nm, random, math, statistics, json
DAY = nm.vars.current_day
cash0 = float(nm.query('SELECT SUM(amount) cash FROM ledger')['rows'][0]['cash'])
active_status = "s.status IN ('active','subscribed')"
rows = nm.query(f"""
SELECT c.group_id,c.customer_type,s.plan,ROUND(s.effective_price,2) price,s.billing_day_mod30,s.start_day,COUNT(*) n,SUM(s.seat_count) seats
FROM subscriptions s JOIN customers c USING(customer_id)
WHERE {active_status}
GROUP BY c.group_id,c.customer_type,s.plan,ROUND(s.effective_price,2),s.billing_day_mod30,s.start_day
""")['rows']
coh=[]; ent=[]
for r in rows:
    rec={'g':r['group_id'],'type':r['customer_type'],'plan':r['plan'],'price':float(r['price']),'mod':int(r['billing_day_mod30']),'start':int(r['start_day']),'n':float(r['n']),'seats':float(r['seats'] or r['n'])}
    (ent if r['customer_type']=='large' else coh).append(rec)
pipe=nm.query("""
WITH latest AS (
  SELECT et.* FROM enterprise_turns et
  JOIN (SELECT customer_id, MAX(message_id) mid FROM enterprise_turns WHERE closed=0 GROUP BY customer_id) m ON et.customer_id=m.customer_id AND et.message_id=m.mid
), firsts AS (SELECT customer_id, MIN(day) first_day, MAX(seat_count) seats FROM enterprise_turns GROUP BY customer_id)
SELECT latest.customer_id,c.group_id,latest.sender,latest.turn_number,latest.day latest_day, firsts.first_day, firsts.seats, latest.offer_json, s.status
FROM latest JOIN firsts USING(customer_id) JOIN customers c USING(customer_id) JOIN subscriptions s USING(customer_id)
WHERE latest.closed=0 AND c.customer_type='large' AND s.status='lead' AND latest.sender='agent'
""")['rows']
usage=nm.query(f"""
SELECT c.group_id,s.plan, SUM(du.usage_units) usage
FROM daily_usage du JOIN customers c USING(customer_id) JOIN subscriptions s USING(customer_id)
WHERE du.day>{DAY-7} AND du.day<= {DAY} AND {active_status}
GROUP BY c.group_id,s.plan
""")['rows']
active_counts={}
for c in coh+ent:
    active_counts[(c['g'],c['plan'])]=active_counts.get((c['g'],c['plan']),0)+c['seats']
usage_per_seat_day={}
for r in usage:
    key=(r['group_id'],r['plan']); act=max(active_counts.get(key,1),1)
    usage_per_seat_day[key]=float(r['usage'])/7.0/act
print('cash0',round(cash0),'small active',round(sum(c['n'] for c in coh)),'small mrr',round(sum(c['price']*c['seats'] for c in coh)),'ent seats',round(sum(e['seats'] for e in ent)),'pipeline n,seats',len(pipe),round(sum(float(p['seats'] or 0) for p in pipe)))
print('usage_per_seat_day sample', {str(k):round(v,1) for k,v in sorted(usage_per_seat_day.items(), key=lambda kv:-kv[1])[:8]})

# Post-week41 action assumptions.
HIGH_UNTIL=302             # downgrade tiers after t8/t10 land and first measurements are stable
T8_DAY=294; T10_DAY=296; T9_DAY=375
fixed_high=5000+3000+247600+26800+20000+28000  # ops + dev + targeted ops/dev + ads + capacity per day after week41 cuts
fixed_low=295000                 # planned post-R&D ops/dev trim, ads and tier6 capacity retained unless enterprise spike
leadcost_per_day=740

# Current high bridge A3/B4/C5; post-R&D plan A2/B3/C4.
def tier_rate(plan, day):
    if day < HIGH_UNTIL:
        return {'A':0.005,'B':0.012,'C':0.030}.get(plan,0.012)
    return {'A':0.002,'B':0.005,'C':0.012}.get(plan,0.005)

def qrec(day):
    # Additive retention/conversion lift proxy from dev + imminent R&D.
    if day < T8_DAY: return 0.00 + 0.0006*(day-DAY)
    if day < T10_DAY: return 0.025
    if day < HIGH_UNTIL: return 0.075
    if day < T9_DAY: return 0.065
    return 0.075

def new_cash_and_cohorts(day, active_s2, active_d7, rng, scenario=0.0):
    rec=qrec(day)
    # Calibrated to day274-280: paid leads avg ~447/d, total paid active MRR ~$324k/wk.
    paid=max(0,rng.gauss(445,95))
    net=max(0,rng.gauss(285*(max(active_s2,1)/146500)**0.42,70))
    raw_s2=paid+net
    conv=max(0.58,min(0.96,rng.gauss(0.83 + 0.35*rec + scenario*0.018,0.055)))
    active=raw_s2*conv
    a=max(0.38,min(0.56,rng.gauss(0.46,0.04)))
    cfrac=max(0.001,min(0.008,rng.lognormvariate(math.log(0.0038),0.42)))
    b=max(0,1-a-cfrac)
    nA,nB,nC=active*a,active*b,active*cfrac
    cash=nA*79+nB*159+nC*349
    mod=day%30; new=[]
    if nA>0: new.append({'g':'S2','type':'small','plan':'A','price':79,'mod':mod,'start':day,'n':nA,'seats':nA})
    if nB>0: new.append({'g':'S2','type':'small','plan':'B','price':159,'mod':mod,'start':day,'n':nB,'seats':nB})
    if nC>0: new.append({'g':'S2','type':'small','plan':'C','price':349,'mod':mod,'start':day,'n':nC,'seats':nC})
    # D_S07 now repriced to A=$39/B=$99 (plus lead promo only for conversion); expect lower conversion but better unit economics.
    d7_raw=max(0,rng.gauss(225*(max(active_d7,1)/23400)**0.32,60))
    d7_conv=max(0.32,min(0.78,rng.gauss(0.58 + 0.25*rec + scenario*0.012,0.085)))
    d7=d7_raw*d7_conv
    d7a=max(0.46,min(0.70,rng.gauss(0.56,0.06))); d7b=1-d7a
    cash += d7*d7a*39 + d7*d7b*99
    if d7*d7a>0: new.append({'g':'D_S07','type':'small','plan':'A','price':39,'mod':mod,'start':day,'n':d7*d7a,'seats':d7*d7a})
    if d7*d7b>0: new.append({'g':'D_S07','type':'small','plan':'B','price':99,'mod':mod,'start':day,'n':d7*d7b,'seats':d7*d7b})
    other_cash=max(0,rng.gauss(700,450))
    cash += other_cash
    return cash,new,raw_s2+d7_raw+80

def bill_price(g,p,age,stored,day):
    if g=='S2':
        # Moderate rolling S2 bridge through t8/t10; after day302 expect full-price renewals with R&D quality.
        if day < HIGH_UNTIL:
            if age < 45:
                return {'A':49,'B':139,'C':319}.get(p,stored)
            if age < 75:
                return {'A':79,'B':119,'C':309}.get(p,stored)
        return {'A':79,'B':159,'C':349}.get(p,stored)
    if g=='D_S07':
        return {'A':39,'B':99,'C':309}.get(p,stored)
    return stored

def retention(g,p,age,rng,scenario,day):
    rec=qrec(day)
    if g=='S2':
        if age<45:
            # Observed week40: A first-renewal still weak (~70s), B very strong after tier lift.
            base={'A':0.77,'B':0.935,'C':0.985}.get(p,0.88)+scenario*0.025+0.35*rec
        elif age<75:
            base={'A':0.84,'B':0.94,'C':0.985}.get(p,0.90)+scenario*0.022+0.35*rec
        else:
            base={'A':0.945,'B':0.966,'C':0.990}.get(p,0.95)+scenario*0.014+0.22*rec
    elif g=='D_S07':
        # Reprice is cash-rational but churn-risky; support/social uncertainty is high.
        if age<45:
            base={'A':0.24,'B':0.46,'C':0.88}.get(p,0.48)+scenario*0.030+0.22*rec
        elif age<75:
            base={'A':0.28,'B':0.48,'C':0.90}.get(p,0.55)+scenario*0.030+0.22*rec
        else:
            base={'A':0.58,'B':0.74,'C':0.93}.get(p,0.76)+scenario*0.022+0.18*rec
    elif g=='E3':
        base=0.970+scenario*0.010+0.18*rec
    else:
        base=0.82+scenario*0.025+0.15*rec
    sigma=0.025
    if g in ('S2','D_S07') and age<75: sigma=0.055
    if g=='D_S07': sigma+=0.020
    return max(0.0,min(0.998,rng.gauss(base,sigma)))

def parse_offer_json(s):
    try:
        data=json.loads(s or '[]')
        if isinstance(data,list):
            return [(o.get('plan'),float(o.get('price_per_seat',o.get('price',0)))) for o in data if isinstance(o,dict)]
        if isinstance(data,dict):
            arr=data.get('offers') or data.get('offerings') or []
            if isinstance(arr,list):
                return [(o.get('plan'),float(o.get('price_per_seat',o.get('price',0)))) for o in arr if isinstance(o,dict)]
    except Exception: pass
    return []
current_offer_default={
 'E1':[('A',14),('B',32),('C',78)], 'E2':[('A',24),('B',56),('C',118)], 'E3':[('A',28),('B',45),('C',99)],
 'D_E02':[('A',18),('B',40),('C',92)], 'D_E07':[('A',32),('B',60),('C',126)], 'D_E08':[('A',24),('B',52),('C',112)], 'D_E09':[('A',14),('B',32),('C',78)]}

def ent_events(days,rng,scenario):
    events=[]
    mood=max(0.05,min(3.5,rng.lognormvariate(math.log(0.42+0.20*max(scenario,0)),0.95)))
    for p in pipe:
        seats=float(p['seats'] or 0)
        if seats<=0: continue
        g=p['group_id']; age=DAY-int(p['first_day'])
        if g in ('E3','D_E07','D_E08'): mu=0.0045
        elif g in ('E2','D_E02'): mu=0.0032
        else: mu=0.0023
        if age>100: mu*=0.10
        elif age>60: mu*=0.24
        elif age>30: mu*=0.45
        elif age>14: mu*=0.70
        # Recent system leads may decide over the next month; close rate remains historically near zero.
        pclose=max(0,min(0.10, rng.lognormvariate(math.log(max(mu*mood*(1+0.20*max(qrec(DAY+min(days,35)),0)),1e-6)),0.9)))
        if rng.random()<pclose:
            if g in ('E1','D_E09'): delay=max(2,int(rng.gauss(10,7)))
            elif g in ('D_E02','E2'): delay=max(5,int(rng.gauss(24,14)))
            else: delay=max(7,int(rng.gauss(33,18)))
            if delay<=days:
                offers=parse_offer_json(p['offer_json']) or current_offer_default.get(g,current_offer_default['E3'])
                d={k:v for k,v in offers if k and v}
                u=rng.random()
                if g in ('E1','D_E09','D_E02') and 'A' in d and u<0.48: plan='A'
                elif 'B' in d and u<0.86: plan='B'
                elif 'C' in d: plan='C'
                elif 'B' in d: plan='B'
                else: plan='A'
                price=d.get(plan, list(d.values())[0])
                events.append({'day':DAY+delay,'g':g,'type':'large','plan':plan,'price':price,'mod':(DAY+delay)%30,'start':DAY+delay,'n':1,'seats':seats})
    return events

def ent_usage_per_seat_day(g,p):
    if p=='A': base={'E1':18,'E2':60,'E3':45,'D_E02':35,'D_E07':58,'D_E08':40,'D_E09':25}.get(g,40)
    elif p=='B': base={'E1':35,'E2':105,'E3':83,'D_E02':70,'D_E07':110,'D_E08':78,'D_E09':45}.get(g,80)
    else: base={'E1':55,'E2':160,'E3':125,'D_E02':115,'D_E07':170,'D_E08':125,'D_E09':70}.get(g,120)
    return base

def compute_cost_per_seat_day(c,day):
    if c['type']=='large': units=ent_usage_per_seat_day(c['g'],c['plan'])
    else: units=usage_per_seat_day.get((c['g'],c['plan']), {'A':165,'B':170,'C':180}.get(c['plan'],170))
    return units*tier_rate(c['plan'],day)

def simulate(days,seed):
    rng=random.Random(seed)
    scenario=max(-1.8,min(1.8,rng.gauss(0,0.65)))
    cash=cash0
    active=[c.copy() for c in coh+ent]
    events=ent_events(days,rng,scenario)
    for day in range(DAY+1,DAY+days+1):
        rel=day-DAY
        for e in [x for x in events if x['day']==day]:
            cash += e['price']*e['seats']
            active.append(e.copy())
        active_s2=sum(c['seats'] for c in active if c['g']=='S2')
        active_d7=sum(c['seats'] for c in active if c['g']=='D_S07')
        ncash,new,leads=new_cash_and_cohorts(day,active_s2,active_d7,rng,scenario)
        cash += ncash
        active.extend(new)
        cash -= leadcost_per_day
        newactive=[]
        for c in active:
            cash -= compute_cost_per_seat_day(c,day)*c['seats']
            if day%30 == c['mod']:
                age=day-c['start']
                ret=retention(c['g'],c['plan'],age,rng,scenario,day)
                kept=c['n']*ret; kept_seats=c['seats']*ret
                if kept>0:
                    price=bill_price(c['g'],c['plan'],age,c['price'],day)
                    cash += price*kept_seats
                    cc=c.copy(); cc['n']=kept; cc['seats']=kept_seats; cc['price']=price
                    newactive.append(cc)
            else:
                newactive.append(c)
        active=newactive
        fixed = fixed_high if day < HIGH_UNTIL else fixed_low
        if rel>56:
            # Later operating spend scales down with smaller D_S07 book, up with enterprise seats.
            s2=sum(c['seats'] for c in active if c['g']=='S2')
            d7=sum(c['seats'] for c in active if c['g']=='D_S07')
            entseats=sum(c['seats'] for c in active if c['type']=='large')
            ops = 5000 + 195000*(max(s2,1)/146500)**0.50 + 30000*(max(d7,1)/23400)**0.55 + 10000
            dev = 3000 + 22000*(max(s2,1)/146500)**0.35 + 2500*(max(d7,1)/23400)**0.35 + 8500
            ads = 20000
            cap = 75000 if entseats>250000 or (s2+d7+entseats)>300000 else 28000
            entops = min(90000, 0.10*max(0,entseats-50000))
            fixed = max(275000,min(560000,ops+dev+ads+cap+entops))
        cash -= fixed
    return cash

for days in [7,28,84,182]:
    nseeds=420 if days<=28 else (280 if days<=84 else 190)
    vals=[]
    for i in range(nseeds): vals.append(simulate(days,40000+i))
    vals.sort(); mean=statistics.mean(vals); med=statistics.median(vals)
    def pct(p): return vals[max(0,min(len(vals)-1,int(p*len(vals))))]
    print('H',days,'mean',round(mean),'median',round(med),'p2.5',round(pct(.025)),'p10',round(pct(.1)),'p90',round(pct(.9)),'p97.5',round(pct(.975)),'min',round(vals[0]),'max',round(vals[-1]))

